import { NextResponse } from "next/server";
import { Liveblocks } from "@liveblocks/node";

export async function POST(request: Request) {
  try {
    const liveblocks = new Liveblocks({
      secret: process.env.LIVEBLOCKS_SECRET_KEY as string,
    });

    const body = await request.json();
    const { room, userId, orgId } = body;

    if (!room || !userId || !orgId) {
      return NextResponse.json({ error: "Missing required fields" }, { status: 400 });
    }

    if (orgId !== "org-a" && orgId !== "org-b") {
      return NextResponse.json({ error: "Invalid orgId" }, { status: 403 });
    }

    if (!room.startsWith(`${orgId}:`)) {
      return NextResponse.json({ error: "Room prefix mismatch" }, { status: 403 });
    }

    const { status, body: lbBody } = await liveblocks.identifyUser(
      {
        userId,
        groupIds: [orgId],
      },
      {
        userInfo: { orgId },
      }
    );

    return new NextResponse(lbBody, { status });
  } catch (error) {
    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }
}

"use client";

import { useSearchParams } from "next/navigation";
import { LiveblocksProvider, RoomProvider, useStorage, useStatus } from "@liveblocks/react";

function RoomContent() {
  const status = useStatus();
  const counter = useStorage((root) => root.counter);

  return (
    <main>
      <h1>Room page</h1>
      <p>Connection status: <span data-testid="connection-status">{status}</span></p>
      <p>Counter: <span data-testid="counter-value">{counter !== null ? counter : "..."}</span></p>
    </main>
  );
}

export default function RoomPage({ params }: { params: { roomId: string } }) {
  const searchParams = useSearchParams();
  const userId = searchParams.get("userId");
  const orgId = searchParams.get("orgId");

  if (!userId || !orgId) {
    return (
      <main>
        <h1>Room page</h1>
        <p>Missing userId or orgId</p>
        <span data-testid="connection-status">disconnected</span>
        <span data-testid="counter-value">0</span>
      </main>
    );
  }

  const authEndpoint = async (room: string) => {
    const response = await fetch("/api/liveblocks-auth", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ room, userId, orgId }),
    });

    if (!response.ok) {
      throw new Error("Authentication failed");
    }

    return await response.json();
  };

  return (
    <LiveblocksProvider authEndpoint={authEndpoint}>
      <RoomProvider id={params.roomId} initialStorage={{ counter: 0 }}>
        <RoomContent />
      </RoomProvider>
    </LiveblocksProvider>
  );
}

